const prev = $('입력값 정리').first().json;

// HTTP Response에서 raw binary data 가져오기
const response = $input.first();
let rawText = '';

// n8n httpRequest는 바이너리 or 텍스트로 올 수 있음
if (response.json && response.json.data) {
  rawText = response.json.data;
} else if (response.json && response.json.body) {
  rawText = response.json.body;
} else {
  rawText = JSON.stringify(response.json);
}

// EUC-KR 깨진 문자 패턴 감지 (\uFFFD 또는 ? 연속)
const isBroken = (rawText.match(/\uFFFD/g) || []).length > 10 || 
                 (rawText.match(/[\x80-\xFF]{3,}/g) || []).length > 5;

let cleanText = rawText;

if (isBroken) {
  // 깨진 문자 제거 후 HTML 태그 파싱
  cleanText = rawText
    .replace(/[\uFFFD\u00B7\u00B8-\u00BF]/g, '')  // 깨진 유니코드
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, ''); // 제어문자
}

// HTML → 텍스트 변환
const text = cleanText
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<').replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"').replace(/&#[0-9]+;/g, '')
  .replace(/\s{2,}/g, ' ').trim();

// 의미있는 한글/영문 텍스트만 추출 (깨진 문자 최소화)
const lines = text.split(' ');
const meaningfulWords = lines.filter(word => {
  // 한글, 영문, 숫자, 일반 특수문자만 허용
  return /[가-힣a-zA-Z0-9]/.test(word);
});

const productInfo = meaningfulWords.join(' ').slice(0, 2000);

return [{
  json: {
    product_url: prev.product_url,
    client_name: prev.client_name,
    client_type: prev.client_type,
    quantity: prev.quantity,
    memo: prev.memo,
    product_info: productInfo || '(제품 정보 파싱 실패 - 납품 정보 기반으로 작성)'
  }
}];

const d = $input.first().json;

// HTTP Request 노드 응답 구조: candidates[0].content.parts[0].text
// Code 노드 응답 구조: gemini_raw (이전 방식)
let raw = '';
if (d.candidates && d.candidates[0]) {
  raw = d.candidates[0]?.content?.parts?.[0]?.text || '';
} else if (d.gemini_raw) {
  raw = d.gemini_raw;
}

raw = raw.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();

let title = '', body = '', hashtags = '';
try {
  const parsed = JSON.parse(raw);
  title = parsed.title || '';
  body = parsed.body || '';
  hashtags = parsed.hashtags || '';
} catch(e) {
  const prev = $('Gemini 프롬프트 조립').first().json;
  title = '[' + (prev.product_name || '납품사례') + '] - 수동편집 필요';
  body = raw;
  hashtags = '#판촉물 #납품사례 #홍보물제작';
}

const prev = $('Gemini 프롬프트 조립').first().json;
const today = new Date().toISOString().slice(0, 10);

return [{ json: {
  title, body, hashtags,
  client_name: prev.client_name,
  client_type: prev.client_type,
  product_name: prev.product_name,
  product_url: prev.product_url || '',
  quantity: prev.quantity,
  memo: prev.memo,
  date: today
} }];

